import Image from 'next/image'
import Link from 'next/link'
import { products, getFeaturedProducts, formatPrice } from '@/lib/products'

// ═══════════════════════════════════════════════════════════════════════════
// HOMEPAGE - "L'Immersion"
// Concept: Scrollytelling luxueux avec hero vidéo, manifeste, et teaser collection
// ═══════════════════════════════════════════════════════════════════════════

export default function HomePage() {
    const featuredProducts = getFeaturedProducts()

    return (
        <div className="relative">
            {/* ═══════════════════════════════════════════════════════════════════
          NAVIGATION FLOTTANTE
          ═══════════════════════════════════════════════════════════════════ */}
            <nav className="fixed top-0 left-0 right-0 z-50 px-6 py-4 md:px-12">
                <div className="flex items-center justify-between">
                    {/* Logo */}
                    <Link
                        href="/"
                        className="font-display text-2xl md:text-3xl text-petrol hover:text-terracotta transition-colors"
                    >
                        Glory<span className="text-gold">.</span>
                    </Link>

                    {/* Menu Desktop */}
                    <div className="hidden md:flex items-center gap-8 font-mono text-sm uppercase tracking-wider">
                        <Link href="/atelier" className="hover:text-terracotta transition-colors">
                            L&apos;Atelier
                        </Link>
                        <Link href="/collection" className="hover:text-terracotta transition-colors">
                            Collection
                        </Link>
                        <Link href="/pro" className="hover:text-terracotta transition-colors">
                            Espace Pro
                        </Link>
                        <Link
                            href="https://wa.me/22500000000"
                            target="_blank"
                            className="btn-gold text-xs py-2 px-4"
                        >
                            Commander
                        </Link>
                    </div>

                    {/* Menu Burger Mobile */}
                    <button className="md:hidden flex flex-col gap-1.5 p-2" aria-label="Menu">
                        <span className="w-6 h-0.5 bg-petrol"></span>
                        <span className="w-4 h-0.5 bg-petrol"></span>
                    </button>
                </div>
            </nav>

            {/* ═══════════════════════════════════════════════════════════════════
          HERO SECTION - Plein écran immersif
          ═══════════════════════════════════════════════════════════════════ */}
            <section className="relative h-screen flex items-center justify-center overflow-hidden">
                {/* Fond avec dégradé et texture */}
                <div className="absolute inset-0 bg-gradient-to-b from-sand via-sand to-sand-300" />

                {/* Pattern décoratif abstrait (en attendant la vidéo) */}
                <div className="absolute inset-0 opacity-5">
                    <div className="absolute top-1/4 left-1/4 w-96 h-96 rounded-full bg-terracotta blur-3xl" />
                    <div className="absolute bottom-1/4 right-1/4 w-72 h-72 rounded-full bg-gold blur-3xl" />
                </div>

                {/* Image produit flottante (placeholder pour vidéo) */}
                <div className="absolute right-[10%] top-1/2 -translate-y-1/2 w-[300px] md:w-[400px] lg:w-[500px] animate-float opacity-90">
                    <Image
                        src="/images/products/etui-wax-abstrait.jpg"
                        alt="Étui Glory Cases en Wax"
                        width={500}
                        height={700}
                        className="rounded-3xl shadow-glass-xl object-cover"
                        priority
                    />
                </div>

                {/* Contenu textuel */}
                <div className="relative z-10 container-luxury text-center md:text-left md:max-w-2xl md:mr-auto">
                    <p className="font-mono text-sm uppercase tracking-[0.3em] text-terracotta mb-4 animate-fade-up">
                        Artisanat d&apos;Abidjan
                    </p>

                    <h1 className="font-display text-5xl md:text-7xl lg:text-8xl leading-none mb-6">
                        Habillons<br />
                        <span className="text-gradient">votre regard</span>
                    </h1>

                    <p className="text-lg md:text-xl text-petrol/70 max-w-md mb-8 font-light">
                        Étuis à lunettes artisanaux faits main. Wax, Cuir, Raphia —
                        L&apos;Afro-Minimalisme au service de l&apos;élégance.
                    </p>

                    <div className="flex flex-col sm:flex-row gap-4 justify-center md:justify-start">
                        <Link href="/collection" className="btn-gold">
                            Découvrir la Collection
                        </Link>
                        <Link href="/atelier" className="btn-outline">
                            Notre Savoir-Faire
                        </Link>
                    </div>
                </div>

                {/* Indicateur de scroll */}
                <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex flex-col items-center gap-2 animate-bounce">
                    <span className="font-mono text-xs uppercase tracking-widest text-petrol/50">Scroll</span>
                    <div className="w-px h-12 bg-gradient-to-b from-petrol/50 to-transparent" />
                </div>
            </section>

            {/* ═══════════════════════════════════════════════════════════════════
          MANIFESTE - Texte révélé au scroll
          ═══════════════════════════════════════════════════════════════════ */}
            <section className="min-h-screen flex items-center justify-center py-32 px-6">
                <div className="max-w-4xl mx-auto text-center">
                    <h2 className="font-display text-4xl md:text-6xl lg:text-7xl leading-tight">
                        <span className="text-petrol">Nous ne fabriquons pas des étuis.</span>
                        <br />
                        <span className="text-terracotta">Nous habillons votre regard.</span>
                    </h2>

                    <div className="divider my-12 max-w-xs mx-auto" />

                    <p className="text-lg md:text-xl text-petrol/70 max-w-2xl mx-auto leading-relaxed">
                        Chaque étui Glory Cases est une pièce unique, confectionnée à la main
                        dans notre atelier d&apos;Abidjan. Nous sélectionnons les plus beaux Wax,
                        les cuirs les plus nobles, pour créer des accessoires qui racontent
                        l&apos;histoire de tout un continent.
                    </p>

                    <div className="mt-12 flex items-center justify-center gap-12 font-mono text-sm">
                        <div className="text-center">
                            <p className="text-4xl font-display text-terracotta">100%</p>
                            <p className="text-petrol/60 uppercase tracking-wider">Fait Main</p>
                        </div>
                        <div className="w-px h-16 bg-petrol/20" />
                        <div className="text-center">
                            <p className="text-4xl font-display text-terracotta">Abidjan</p>
                            <p className="text-petrol/60 uppercase tracking-wider">Côte d&apos;Ivoire</p>
                        </div>
                        <div className="w-px h-16 bg-petrol/20" />
                        <div className="text-center">
                            <p className="text-4xl font-display text-terracotta">Unique</p>
                            <p className="text-petrol/60 uppercase tracking-wider">Chaque Pièce</p>
                        </div>
                    </div>
                </div>
            </section>

            {/* ═══════════════════════════════════════════════════════════════════
          TEASER COLLECTION - Marquee Horizontal
          ═══════════════════════════════════════════════════════════════════ */}
            <section className="py-20 overflow-hidden bg-petrol">
                <div className="mb-12 text-center">
                    <p className="font-mono text-sm uppercase tracking-[0.3em] text-gold mb-4">
                        Nos Créations
                    </p>
                    <h2 className="font-display text-4xl md:text-5xl text-white">
                        La Collection
                    </h2>
                </div>

                {/* Marquee infini */}
                <div className="relative flex overflow-x-hidden">
                    <div className="flex gap-8 animate-marquee">
                        {[...products, ...products].map((product, index) => (
                            <Link
                                key={`${product.id}-${index}`}
                                href={`/product/${product.slug}`}
                                className="group relative flex-shrink-0 w-[280px] md:w-[350px]"
                            >
                                <div className="relative aspect-product rounded-2xl overflow-hidden">
                                    <Image
                                        src={product.images[0]}
                                        alt={product.title}
                                        fill
                                        className="object-cover transition-transform duration-700 group-hover:scale-110"
                                    />
                                    {/* Overlay au hover */}
                                    <div className="absolute inset-0 bg-gradient-to-t from-petrol/80 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

                                    {/* Badge Nouveau */}
                                    {product.new && (
                                        <span className="absolute top-4 left-4 px-3 py-1 bg-gold text-white text-xs font-mono uppercase rounded-full">
                                            Nouveau
                                        </span>
                                    )}

                                    {/* Info produit */}
                                    <div className="absolute bottom-0 left-0 right-0 p-6 text-white translate-y-full group-hover:translate-y-0 transition-transform duration-300">
                                        <h3 className="font-display text-xl">{product.title}</h3>
                                        <p className="font-mono text-sm text-gold">{formatPrice(product.price)}</p>
                                    </div>
                                </div>
                            </Link>
                        ))}
                    </div>
                </div>

                {/* CTA */}
                <div className="mt-12 text-center">
                    <Link href="/collection" className="btn-gold">
                        Voir Toute la Collection
                    </Link>
                </div>
            </section>

            {/* ═══════════════════════════════════════════════════════════════════
          SECTION MATIÈRES
          ═══════════════════════════════════════════════════════════════════ */}
            <section className="py-32 px-6">
                <div className="max-w-6xl mx-auto">
                    <div className="text-center mb-16">
                        <p className="font-mono text-sm uppercase tracking-[0.3em] text-terracotta mb-4">
                            L&apos;Excellence des Matériaux
                        </p>
                        <h2 className="font-display text-4xl md:text-5xl">
                            Nos Matières Nobles
                        </h2>
                    </div>

                    <div className="grid md:grid-cols-3 gap-8">
                        {/* Wax */}
                        <div className="glass-card p-8 text-center group cursor-pointer">
                            <div className="w-20 h-20 mx-auto mb-6 rounded-full bg-gradient-to-br from-terracotta to-gold flex items-center justify-center text-white text-3xl group-hover:scale-110 transition-transform">
                                🎨
                            </div>
                            <h3 className="font-display text-2xl mb-3">Wax</h3>
                            <p className="text-petrol/70">
                                Tissu emblématique aux motifs vibrants, chaque pièce raconte une histoire unique.
                            </p>
                        </div>

                        {/* Cuir */}
                        <div className="glass-card p-8 text-center group cursor-pointer">
                            <div className="w-20 h-20 mx-auto mb-6 rounded-full bg-gradient-to-br from-petrol to-petrol-400 flex items-center justify-center text-white text-3xl group-hover:scale-110 transition-transform">
                                🛡️
                            </div>
                            <h3 className="font-display text-2xl mb-3">Cuir</h3>
                            <p className="text-petrol/70">
                                Cuir tanné traditionnellement, souple et résistant pour une durabilité exceptionnelle.
                            </p>
                        </div>

                        {/* Raphia */}
                        <div className="glass-card p-8 text-center group cursor-pointer">
                            <div className="w-20 h-20 mx-auto mb-6 rounded-full bg-gradient-to-br from-gold to-sand-500 flex items-center justify-center text-petrol text-3xl group-hover:scale-110 transition-transform">
                                🌿
                            </div>
                            <h3 className="font-display text-2xl mb-3">Raphia</h3>
                            <p className="text-petrol/70">
                                Fibre naturelle tressée à la main, légère et écologique pour un style bohème.
                            </p>
                        </div>
                    </div>
                </div>
            </section>

            {/* ═══════════════════════════════════════════════════════════════════
          ESPACE PRO TEASER
          ═══════════════════════════════════════════════════════════════════ */}
            <section className="py-32 px-6 bg-petrol text-white">
                <div className="max-w-4xl mx-auto text-center">
                    <p className="font-mono text-sm uppercase tracking-[0.3em] text-gold mb-4">
                        Pour les Entreprises
                    </p>
                    <h2 className="font-display text-4xl md:text-5xl mb-6">
                        Cadeaux d&apos;Affaires Premium
                    </h2>
                    <p className="text-lg text-white/70 mb-8 max-w-2xl mx-auto">
                        Offrez à vos collaborateurs et clients des étuis personnalisés à l&apos;image de votre marque.
                        Gravure logo, packaging luxe, livraison internationale.
                    </p>
                    <Link href="/pro" className="btn-gold">
                        Demander un Devis
                    </Link>
                </div>
            </section>

            {/* ═══════════════════════════════════════════════════════════════════
          FOOTER
          ═══════════════════════════════════════════════════════════════════ */}
            <footer className="py-16 px-6 border-t border-petrol/10">
                <div className="max-w-6xl mx-auto">
                    <div className="grid md:grid-cols-4 gap-12">
                        {/* Logo & Description */}
                        <div className="md:col-span-2">
                            <Link href="/" className="font-display text-3xl text-petrol">
                                Glory<span className="text-gold">.</span>
                            </Link>
                            <p className="mt-4 text-petrol/60 max-w-sm">
                                Étuis à lunettes artisanaux faits main à Abidjan.
                                L&apos;Afro-Minimalisme au service de votre regard.
                            </p>
                        </div>

                        {/* Navigation */}
                        <div>
                            <h4 className="font-mono text-sm uppercase tracking-wider text-petrol mb-4">Navigation</h4>
                            <ul className="space-y-2 text-petrol/70">
                                <li><Link href="/collection" className="hover:text-terracotta transition-colors">Collection</Link></li>
                                <li><Link href="/atelier" className="hover:text-terracotta transition-colors">L&apos;Atelier</Link></li>
                                <li><Link href="/pro" className="hover:text-terracotta transition-colors">Espace Pro</Link></li>
                            </ul>
                        </div>

                        {/* Contact */}
                        <div>
                            <h4 className="font-mono text-sm uppercase tracking-wider text-petrol mb-4">Contact</h4>
                            <ul className="space-y-2 text-petrol/70">
                                <li>Abidjan, Côte d&apos;Ivoire</li>
                                <li>
                                    <a
                                        href="https://wa.me/22500000000"
                                        target="_blank"
                                        rel="noopener noreferrer"
                                        className="hover:text-terracotta transition-colors"
                                    >
                                        WhatsApp
                                    </a>
                                </li>
                                <li>
                                    <a
                                        href="mailto:hello@glorycases.com"
                                        className="hover:text-terracotta transition-colors"
                                    >
                                        hello@glorycases.com
                                    </a>
                                </li>
                            </ul>
                        </div>
                    </div>

                    <div className="divider my-12" />

                    <div className="flex flex-col md:flex-row items-center justify-between gap-4 text-sm text-petrol/50">
                        <p>© 2024 Glory Cases. Tous droits réservés.</p>
                        <p className="font-mono">Fait avec ♥ à Abidjan</p>
                    </div>
                </div>
            </footer>
        </div>
    )
}
